from inventory.events import MemoryPublisher
from inventory.ledger import InventoryLedger
from inventory.service import ReservationService


def test_parallel_tenant_retries_produce_two_independent_effects():
    ledger = InventoryLedger()
    ledger.set_stock("north", "cable", 8)
    ledger.set_stock("south", "cable", 8)
    publisher = MemoryPublisher()
    service = ReservationService(ledger, publisher)

    for tenant, quantity in (("north", 2), ("south", 3)):
        service.reserve(tenant, "mobile-42", "cable", quantity, attempt=1)
        service.reserve(tenant, "mobile-42", "cable", quantity, attempt=7)

    remaining = {
        tenant: ledger.stock(tenant, "cable")
        for tenant in ("north", "south")
    }
    event_ids = {message["event_id"] for message in publisher.messages}

    assert remaining == {"north": 6, "south": 5}
    assert len(publisher.messages) == 2
    assert len(event_ids) == 2
